import{_ as a,o as s,c as t,aw as e}from"./chunks/framework.Dq2onT5h.js";const n=JSON.parse('{"title":"Contract Size Limits","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Contract Size Limits | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"ev-reth/features/contract-size-limits.md","filePath":"ev-reth/features/contract-size-limits.md","lastUpdated":1772446570000}');const o=a({name:"ev-reth/features/contract-size-limits.md"},[["render",function(a,n,o,l,i,r){return s(),t("div",null,[...n[0]||(n[0]=[e('<h1 id="contract-size-limits" tabindex="-1">Contract Size Limits <a class="header-anchor" href="#contract-size-limits" aria-label="Permalink to &quot;Contract Size Limits&quot;">​</a></h1><p>Increase the maximum contract bytecode size beyond Ethereum&#39;s 24KB limit.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Ethereum limits contract size to 24,576 bytes (24KB) via <a href="https://eips.ethereum.org/EIPS/eip-170" target="_blank" rel="noreferrer">EIP-170</a>. ev-reth allows increasing this limit for use cases requiring larger contracts:</p><ul><li>Complex DeFi protocols</li><li>On-chain game logic</li><li>ZK verification contracts</li></ul><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>In your chainspec (<code>genesis.json</code>):</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#767676;">{</span></span>\n<span class="line"><span style="color:#94EEFF77;">  &quot;</span><span style="color:#94EEFF;">config</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#94EEFF77;">    &quot;</span><span style="color:#94EEFF;">evolve</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#94EEFF77;">      &quot;</span><span style="color:#94EEFF;">contractSizeLimit</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> 49152</span></span>\n<span class="line"><span style="color:#767676;">    }</span></span>\n<span class="line"><span style="color:#767676;">  }</span></span>\n<span class="line"><span style="color:#767676;">}</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Field</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><code>contractSizeLimit</code></td><td>Max bytecode size in bytes</td><td>24576 (24KB)</td></tr></tbody></table><h2 id="common-values" tabindex="-1">Common Values <a class="header-anchor" href="#common-values" aria-label="Permalink to &quot;Common Values&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Size</th><th>Bytes</th><th>Use Case</th></tr></thead><tbody><tr><td>24KB</td><td>24576</td><td>Ethereum default</td></tr><tr><td>48KB</td><td>49152</td><td>2x limit</td></tr><tr><td>64KB</td><td>65536</td><td>2.67x limit</td></tr><tr><td>128KB</td><td>131072</td><td>Large contracts</td></tr></tbody></table><h2 id="trade-offs" tabindex="-1">Trade-offs <a class="header-anchor" href="#trade-offs" aria-label="Permalink to &quot;Trade-offs&quot;">​</a></h2><p><strong>Pros:</strong></p><ul><li>Deploy larger, more complex contracts</li><li>Avoid splitting logic across multiple contracts</li><li>Simpler contract architecture</li></ul><p><strong>Cons:</strong></p><ul><li>Higher deployment gas costs</li><li>Longer deployment times</li><li>May impact block gas limits</li></ul><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2><p>Allow contracts up to 64KB:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#767676;">{</span></span>\n<span class="line"><span style="color:#94EEFF77;">  &quot;</span><span style="color:#94EEFF;">config</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#94EEFF77;">    &quot;</span><span style="color:#94EEFF;">chainId</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> 1337</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF77;">    &quot;</span><span style="color:#94EEFF;">evolve</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#94EEFF77;">      &quot;</span><span style="color:#94EEFF;">contractSizeLimit</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> 65536</span></span>\n<span class="line"><span style="color:#767676;">    }</span></span>\n<span class="line"><span style="color:#767676;">  }</span></span>\n<span class="line"><span style="color:#767676;">}</span></span></code></pre></div><h2 id="considerations" tabindex="-1">Considerations <a class="header-anchor" href="#considerations" aria-label="Permalink to &quot;Considerations&quot;">​</a></h2><ul><li>This is a chain-wide setting—affects all deployments</li><li>Existing tooling may warn about large contracts</li><li>Consider gas costs for deployment and interaction</li></ul>',21)])])}]]);export{n as __pageData,o as default};
